import React, { useState, useMemo, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';
import { UploadCloud, Trash2, RefreshCw, FolderClosed, Image } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import MediaLibrary from './media/MediaLibrary';
import { FileUploader } from './media/FileUploader';
import { FileStats } from './media/FileStats';
import { useToast } from '@/components/ui/use-toast';
import { useMedia } from '@/hooks/useMedia';
import { AdminPageLayout, PageHeader } from '@/templates/flowbite-admin';
import useSplatSegments from '@/hooks/useSplatSegments';

const FilesManager = () => {
  const [isUploadOpen, setIsUploadOpen] = useState(false);
  const [refreshTrigger, setRefreshTrigger] = useState(0);
  const navigate = useNavigate();
  const location = useLocation();
  const segments = useSplatSegments();
  const showTrash = segments[0] === 'trash';
  const basePath = useMemo(() => (
    location.pathname.startsWith('/cmspanel/media') ? '/cmspanel/media' : '/cmspanel/files'
  ), [location.pathname]);

  // Category State
  const [categories, setCategories] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [isCreateCategoryOpen, setIsCreateCategoryOpen] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  // Use new statsLoading prop
  const { uploadFile, uploading, syncFiles, syncing, stats, statsLoading, fetchCategories, createCategory } = useMedia();
  const { toast } = useToast();

  const loadCategories = React.useCallback(async () => {
    const data = await fetchCategories();
    setCategories(data);
  }, [fetchCategories]);

  // Load categories on mount
  React.useEffect(() => {
    loadCategories();
  }, [loadCategories]);

  useEffect(() => {
    if (segments.length > 0 && segments[0] !== 'trash') {
      navigate(basePath, { replace: true });
      return;
    }

    if (segments[0] === 'trash' && segments.length > 1) {
      navigate(`${basePath}/trash`, { replace: true });
    }
  }, [segments, basePath, navigate]);

  useEffect(() => {
    if (showTrash) setSelectedCategory(null);
  }, [showTrash]);

  const handleCreateCategory = async () => {
    if (!newCategoryName.trim()) return;
    const newCat = await createCategory(newCategoryName);
    if (newCat) {
      setNewCategoryName('');
      setIsCreateCategoryOpen(false);
      loadCategories();
    }
  };

  const handleUpload = async (acceptedFiles) => {
    let successCount = 0;
    for (const file of acceptedFiles) {
      try {
        // Pass selectedCategory to uploadFile
        await uploadFile(file, '', selectedCategory);
        successCount++;
      } catch (err) {
        toast({ variant: 'destructive', title: `Failed to upload ${file.name}`, description: err.message });
      }
    }
    if (successCount > 0) {
      toast({ title: 'Success', description: `${successCount} files uploaded successfully.` });
      setIsUploadOpen(false);
      setRefreshTrigger(prev => prev + 1);
    }
  };

  const handleSync = async () => {
    const success = await syncFiles();
    if (success) setRefreshTrigger(prev => prev + 1);
  };

  const breadcrumbs = [
    { label: 'Media Library', icon: Image, href: showTrash ? basePath : undefined },
    ...(showTrash ? [{ label: 'Trash Bin', icon: Trash2 }] : [])
  ];

  const headerActions = (
    <div className="flex items-center gap-3">
      {!showTrash && (
        <Button
          variant="outline"
          onClick={handleSync}
          disabled={syncing}
          title="Sync files from Storage Bucket if missing in DB"
        >
          <RefreshCw className={`w-4 h-4 mr-2 ${syncing ? 'animate-spin' : ''}`} />
          {syncing ? 'Syncing...' : 'Sync Storage'}
        </Button>
      )}

      <Button
        variant={showTrash ? "outline" : "outline"}
        onClick={() => {
          navigate(showTrash ? basePath : `${basePath}/trash`);
        }}
        className={`transition-colors border-border ${showTrash ? 'bg-muted text-foreground' : 'text-muted-foreground hover:text-foreground'}`}
      >
        {showTrash ? (
          <>
            <FolderClosed className="w-4 h-4 mr-2" />
            Back to Library
          </>
        ) : (
          <>
            <Trash2 className="w-4 h-4 mr-2 text-destructive" />
            Trash Bin
          </>
        )}
      </Button>

      {!showTrash && (
        <Dialog open={isUploadOpen} onOpenChange={setIsUploadOpen}>
          <DialogTrigger asChild>
            <Button className="shadow-sm">
              <UploadCloud className="w-4 h-4 mr-2" />
              Upload Files
            </Button>
          </DialogTrigger>
          <DialogContent className="sm:max-w-xl">
            <DialogHeader>
              <DialogTitle>Upload Files</DialogTitle>
              <DialogDescription>
                Drag and drop files here to upload directly to your media library. Supported formats: JPG, PNG, WEBP, PDF.
                {selectedCategory && categories.find(c => c.id === selectedCategory) && (
                  <span className="block mt-2 text-blue-600 font-medium">
                    Uploading to category: {categories.find(c => c.id === selectedCategory)?.name}
                  </span>
                )}
              </DialogDescription>
            </DialogHeader>
            <div className="mt-4">
              <FileUploader onUpload={handleUpload} uploading={uploading} />
            </div>
          </DialogContent>
        </Dialog>
      )}
    </div>
  );

  return (
    <AdminPageLayout>
      <Helmet>
        <title>{showTrash ? 'Trash - Media Library' : 'Media Library - CMS'}</title>
      </Helmet>

      <PageHeader
        title={showTrash ? 'Trash Bin' : 'Media Library'}
        description={showTrash
          ? 'Manage deleted files. You can restore them when needed.'
          : 'Manage and organize all your digital assets, images, and documents.'}
        breadcrumbs={breadcrumbs}
        actions={headerActions}
      />

      <div className="flex flex-col space-y-6">
        {/* Stats Cards (Only show in main view) */}
        {!showTrash && (
          <div className="flex-shrink-0">
            <FileStats stats={stats} loading={statsLoading} />
          </div>
        )}

        <div className="flex flex-col md:flex-row gap-6 items-start">
          {/* Sidebar for Categories */}
          {!showTrash && (
            <div className="w-full md:w-64 flex-shrink-0 space-y-4">
              <div className="bg-card rounded-xl border border-border shadow-sm p-4">
                <div className="flex items-center justify-between mb-4">
                  <h3 className="font-semibold text-sm text-foreground">Categories</h3>
                  <Dialog open={isCreateCategoryOpen} onOpenChange={setIsCreateCategoryOpen}>
                    <DialogTrigger asChild>
                      <Button variant="ghost" size="icon" className="h-6 w-6">
                        <div className="h-4 w-4" >+</div>
                      </Button>
                    </DialogTrigger>
                    <DialogContent>
                      <DialogHeader>
                        <DialogTitle>Create Category</DialogTitle>
                        <DialogDescription>Add a new category to organize your files.</DialogDescription>
                      </DialogHeader>
                      <div className="space-y-4 py-2">
                        <div className="space-y-2">
                          <label className="text-sm font-medium">Category Name</label>
                          <input
                            className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                            value={newCategoryName}
                            onChange={(e) => setNewCategoryName(e.target.value)}
                            placeholder="e.g. Marketing, Products"
                          />
                        </div>
                        <Button onClick={handleCreateCategory} disabled={!newCategoryName.trim()}>Create</Button>
                      </div>
                    </DialogContent>
                  </Dialog>
                </div>

                <div className="space-y-1">
                  <Button
                    variant={selectedCategory === null ? "secondary" : "ghost"}
                    className="w-full justify-start font-normal"
                    onClick={() => setSelectedCategory(null)}
                  >
                    <FolderClosed className="w-4 h-4 mr-2" />
                    All Files
                  </Button>
                  {categories.map(cat => (
                    <Button
                      key={cat.id}
                      variant={selectedCategory === cat.id ? "secondary" : "ghost"}
                      className="w-full justify-start font-normal truncate"
                      onClick={() => setSelectedCategory(cat.id)}
                      title={cat.name}
                    >
                      <div className="w-4 h-4 mr-2 flex items-center justify-center">#</div>
                      <span className="truncate">{cat.name}</span>
                    </Button>
                  ))}
                </div>
              </div>
            </div>
          )}

          {/* Main Content Area */}
          <div className="flex-1 w-full bg-card rounded-xl border border-border shadow-sm overflow-hidden min-h-[500px]">
            <MediaLibrary
              refreshTrigger={refreshTrigger}
              isTrashView={showTrash}
              categoryId={selectedCategory}
            />
          </div>
        </div>
      </div>
    </AdminPageLayout>
  );
}

export default FilesManager;

import { useState, useMemo, useCallback, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import GenericContentManager from '@/components/dashboard/GenericContentManager';
import VisualPageBuilder from '@/components/visual-builder/VisualPageBuilder';
import { AdminPageLayout, PageHeader, PageTabs, TabsContent } from '@/templates/flowbite-admin';
import { FileText, FolderOpen, Layers, Paintbrush, Tags } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useTranslation } from 'react-i18next';
import useSplatSegments from '@/hooks/useSplatSegments';

/**
 * PagesManager - Manages pages with Visual Builder support.
 * Refactored to use awadmintemplate01 components for consistent UI.
 */
function PagesManager({ onlyVisual = false }) {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const segments = useSplatSegments();
  const tabValues = ['pages', 'categories', 'tags'];
  const isTrashView = segments[0] === 'trash';
  const hasTabSegment = tabValues.includes(segments[0]);
  const activeTab = hasTabSegment ? segments[0] : 'pages';
  const hasExtraSegment = segments.length > 1;
  const hasValidTrashSuffix = segments[1] === 'trash';
  const [visualBuilderPage, setVisualBuilderPage] = useState(null);
  const [selectedLanguage, setSelectedLanguage] = useState('en');

  // Language options
  const languages = [
    { value: 'en', label: 'English' },
    { value: 'id', label: 'Bahasa Indonesia' }
  ];

  // Tab definitions
  const tabs = useMemo(() => onlyVisual ? [] : [
    { value: 'pages', label: t('pages.tabs.pages'), icon: FileText, color: 'blue' },
    { value: 'categories', label: t('pages.tabs.categories'), icon: FolderOpen, color: 'purple' },
    { value: 'tags', label: t('pages.tabs.tags') || 'Tags', icon: Tags, color: 'green' },
  ], [onlyVisual, t]);

  useEffect(() => {
    if (!onlyVisual && segments.length > 0 && !hasTabSegment && !isTrashView) {
      navigate('/cmspanel/pages', { replace: true });
      return;
    }

    if (!onlyVisual && hasTabSegment && hasExtraSegment && !hasValidTrashSuffix) {
      const basePath = activeTab === 'pages' ? '/cmspanel/pages' : `/cmspanel/pages/${activeTab}`;
      navigate(basePath, { replace: true });
      return;
    }

    if (!onlyVisual && isTrashView && segments.length > 1) {
      navigate('/cmspanel/pages/trash', { replace: true });
    }
  }, [onlyVisual, segments, hasTabSegment, hasExtraSegment, hasValidTrashSuffix, isTrashView, activeTab, navigate]);

  // Dynamic breadcrumb based on active tab
  const breadcrumbs = useMemo(() => [
    { label: onlyVisual ? t('pages.breadcrumbs.visual_pages') : t('pages.breadcrumbs.pages'), href: activeTab !== 'pages' || isTrashView ? '/cmspanel/pages' : undefined, icon: Layers },
    ...(isTrashView ? [{ label: t('common.trash') }] : []),
    ...(activeTab !== 'pages' && !onlyVisual ? [{ label: t('pages.breadcrumbs.categories') }] : []),
  ], [onlyVisual, activeTab, isTrashView, t]);

  // Page columns with editor type indicator
  const pageColumns = useMemo(() => [
    { key: 'title', label: t('pages.columns.title'), className: 'font-medium' },
    { key: 'slug', label: t('pages.columns.path') },
    {
      key: 'locale',
      label: t('common.language') || 'Language',
      render: (value) => (
        <span className="uppercase text-xs font-bold text-muted-foreground border px-1 rounded">
          {value || 'en'}
        </span>
      )
    },
    {
      key: 'page_type',
      label: t('pages.columns.type'),
      render: (value) => {
        const colors = {
          homepage: 'bg-primary/10 text-primary border-primary/20',
          header: 'bg-muted text-muted-foreground border-border',
          footer: 'bg-muted text-muted-foreground border-border',
          single_page: 'bg-secondary text-secondary-foreground',
          single_post: 'bg-secondary text-secondary-foreground',
          '404': 'bg-destructive/10 text-destructive border-destructive/20',
          regular: 'bg-card text-card-foreground border-border border'
        };
        const labels = {
          homepage: t('pages.badges.homepage'),
          header: t('pages.badges.header'),
          footer: t('pages.badges.footer'),
          single_page: t('pages.badges.single_page'),
          single_post: t('pages.badges.single_post'),
          '404': t('pages.badges.404'),
          regular: t('pages.badges.regular')
        };
        return (
          <span className={`px-2 py-0.5 text-xs rounded-full font-medium border ${colors[value] || colors.regular}`}>
            {labels[value] || value || t('pages.badges.regular')}
          </span>
        );
      }
    },
    {
      key: 'category',
      label: t('pages.columns.category'),
      render: (value, row) => (
        <span className="text-sm text-muted-foreground">
          {row.category?.name || '-'}
        </span>
      )
    },
    {
      key: 'editor_type',
      label: t('pages.columns.editor'),
      render: (value) => (
        <span className={`px-2 py-0.5 text-xs rounded-full border ${value === 'visual'
          ? 'bg-accent/10 text-accent-foreground border-accent/20'
          : 'bg-muted text-muted-foreground border-border'
          }`}>
          {value === 'visual' ? `🎨 ${t('pages.badges.visual')}` : `📝 ${t('pages.badges.richtext')}`}
        </span>
      )
    },
    { key: 'status', label: t('pages.columns.status') },
    { key: 'published_at', label: t('pages.columns.published'), type: 'date' },
    { key: 'updated_at', label: t('pages.columns.updated'), type: 'date' }
  ], [t]);

  const pageFormFields = useMemo(() => [
    { key: 'title', label: t('pages.form.title'), required: true },
    {
      key: 'page_type',
      label: t('pages.form.page_type'),
      type: 'select',
      options: [
        { value: 'regular', label: t('pages.form.page_type_regular') }
      ],
      defaultValue: 'regular',
      description: t('pages.form.page_type_desc')
    },
    { key: 'slug', label: t('pages.form.slug'), required: true },
    {
      key: 'locale',
      label: t('common.language'),
      type: 'select',
      options: languages,
      defaultValue: selectedLanguage,
      description: 'Language of this page'
    },
    {
      key: 'status', label: t('pages.form.status'), type: 'select', options: [
        { value: 'published', label: t('pages.form.status_published') },
        { value: 'draft', label: t('pages.form.status_draft') }
      ]
    },
    {
      key: 'editor_type', label: t('pages.form.editor_type'), type: 'select', options: [
        { value: 'richtext', label: `📝 ${t('pages.form.editor_richtext')}` },
        { value: 'visual', label: `🎨 ${t('pages.form.editor_visual')}` }
      ],
      defaultValue: onlyVisual ? 'visual' : 'richtext',
      description: t('pages.form.editor_desc'),
    },
    { key: 'category_id', label: t('pages.form.category'), type: 'resource_select', resourceTable: 'categories', filter: { type: 'page' } },
    { key: 'tags', label: t('pages.form.tags') || 'Tags', type: 'tag_input', description: t('pages.form.tags_desc') || 'Add tags to organize your content' },
    {
      key: 'content',
      label: t('pages.form.content'),
      type: 'richtext',
      description: t('pages.form.content_desc'),
      conditionalShow: (formData) => formData.editor_type !== 'visual'
    },
    { key: 'excerpt', label: t('pages.form.excerpt'), type: 'textarea' },
    { key: 'featured_image', label: t('pages.form.featured_image'), type: 'image' },
    // SEO Fields
    { key: 'meta_title', label: t('pages.form.meta_title') || 'Meta Title', type: 'text', description: 'SEO title (60 chars recommended)' },
    { key: 'meta_description', label: t('pages.form.meta_desc'), type: 'textarea' },
    { key: 'meta_keywords', label: t('pages.form.meta_keywords') || 'Meta Keywords', type: 'text', description: 'Comma-separated keywords' },
    { key: 'og_image', label: t('pages.form.og_image') || 'OG Image', type: 'image', description: 'Social sharing image (1200x630 recommended)' },
    { key: 'canonical_url', label: t('pages.form.canonical_url') || 'Canonical URL', type: 'text', description: 'Full URL if this content exists elsewhere' },
    { key: 'is_active', label: t('pages.form.active'), type: 'boolean' }
  ], [onlyVisual, t]);

  // Custom row actions for Visual Builder
  const customRowActions = useCallback((page) => {
    if (page.editor_type === 'visual') {
      return (
        <Button
          size="sm"
          onClick={(e) => {
            e.stopPropagation();
            setVisualBuilderPage(page);
          }}
          variant="outline"
          className="h-7 px-2 text-xs border-accent text-accent-foreground hover:bg-accent/10"
          title={t('pages.action_edit_visual')}
        >
          <Paintbrush className="w-3 h-3 mr-1.5" />
          {t('pages.action_edit_visual')}
        </Button>
      );
    }
    return null;
  }, [t]);

  // Category columns and fields
  const categoryColumns = useMemo(() => [
    { key: 'name', label: t('pages.category.name'), className: 'font-medium' },
    { key: 'slug', label: t('pages.category.slug') },
    { key: 'description', label: t('pages.category.description') },
    { key: 'created_at', label: t('pages.category.created'), type: 'date' }
  ], [t]);

  const categoryFormFields = useMemo(() => [
    { key: 'name', label: t('pages.category.form.name'), required: true },
    { key: 'slug', label: t('pages.category.form.slug') },
    { key: 'description', label: t('pages.category.form.description'), type: 'textarea' },
    {
      key: 'type', label: t('pages.category.form.type'), type: 'select', options: [
        { value: 'page', label: t('pages.category.form.type_page') },
        { value: 'blog', label: t('pages.category.form.type_blog') },
        { value: 'product', label: t('pages.category.form.type_product') }
      ], defaultValue: 'page'
    }
  ], [t]);

  // If Visual Builder is open, show it full screen
  if (visualBuilderPage) {
    return (
      <VisualPageBuilder
        page={visualBuilderPage}
        onClose={() => setVisualBuilderPage(null)}
        onSuccess={() => setVisualBuilderPage(null)}
      />
    );
  }

  return (
    <AdminPageLayout requiredPermission={onlyVisual ? "tenant.visual_pages.read" : "tenant.pages.read"}>
      {/* Page Header with Breadcrumbs */}
      <PageHeader
        title={onlyVisual ? t('pages.visual_title') : t('pages.title')}
        description={onlyVisual ? t('pages.visual_desc') : t('pages.subtitle')}
        icon={Layers}
        breadcrumbs={breadcrumbs}
      />

      {/* Tabs Navigation (hidden for onlyVisual mode) */}
      {onlyVisual ? (
        <GenericContentManager
          tableName="pages"
          resourceName={t('pages.visual_title')} // Or generic "Visual Page" if strictly needed in singular, but title works
          columns={pageColumns}
          formFields={pageFormFields}
          permissionPrefix="visual_pages"
          customRowActions={customRowActions}
          defaultFilters={{ editor_type: 'visual', locale: selectedLanguage }}
          showBreadcrumbs={false}
          customToolbarActions={() => (
            <div className="flex items-center gap-2 mr-2">
              <select
                className="h-9 w-32 rounded-md border border-input bg-background px-3 py-1 text-sm shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                value={selectedLanguage}
                onChange={(e) => setSelectedLanguage(e.target.value)}
              >
                {languages.map((lang) => (
                  <option key={lang.value} value={lang.value}>
                    {lang.label}
                  </option>
                ))}
              </select>
            </div>
          )}
        />
      ) : (
        <PageTabs
          value={activeTab}
          onValueChange={(value) => {
            navigate(value === 'pages' ? '/cmspanel/pages' : `/cmspanel/pages/${value}`);
          }}
          tabs={tabs}
        >
          <TabsContent value="pages" className="mt-0">
            <GenericContentManager
              tableName="pages"
              resourceName={t('pages.badges.regular')}
              columns={pageColumns}
              formFields={pageFormFields}
              permissionPrefix="pages"
              defaultFilters={{ page_type: 'regular', locale: selectedLanguage }}
              customSelect="*, category:categories!pages_category_id_fkey(id, name), owner:users!created_by(email, full_name), tenant:tenants(name)"
              customRowActions={customRowActions}
              showBreadcrumbs={false}
              customToolbarActions={() => (
                <div className="flex items-center gap-2 mr-2">
                  <select
                    className="h-9 w-32 rounded-md border border-input bg-background px-3 py-1 text-sm shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                    value={selectedLanguage}
                    onChange={(e) => setSelectedLanguage(e.target.value)}
                  >
                    {languages.map((lang) => (
                      <option key={lang.value} value={lang.value}>
                        {lang.label}
                      </option>
                    ))}
                  </select>
                </div>
              )}
            />
          </TabsContent>

          <TabsContent value="categories" className="mt-0">
            <GenericContentManager
              tableName="categories"
              resourceName={t('pages.category.form.type_page')} // Or Category singular
              columns={categoryColumns}
              formFields={categoryFormFields}
              permissionPrefix="categories"
              customSelect="*, owner:users!created_by(email, full_name), tenant:tenants(name)"
              defaultFilters={{ type: 'page' }}
              showBreadcrumbs={false}
            />
          </TabsContent>

          <TabsContent value="tags" className="mt-0">
            <GenericContentManager
              tableName="tags"
              resourceName={t('pages.tags.singular') || 'Tag'}
              columns={[
                { key: 'name', label: t('pages.tags.name') || 'Name', className: 'font-medium' },
                { key: 'slug', label: t('pages.tags.slug') || 'Slug' },
                { key: 'created_at', label: t('pages.tags.created') || 'Created', type: 'date' }
              ]}
              formFields={[
                { key: 'name', label: t('pages.tags.form.name') || 'Name', required: true },
                { key: 'slug', label: t('pages.tags.form.slug') || 'Slug' }
              ]}
              permissionPrefix="tags"
              customSelect="*, owner:users!created_by(email, full_name), tenant:tenants(name)"
              showBreadcrumbs={false}
            />
          </TabsContent>
        </PageTabs>
      )}
    </AdminPageLayout>
  );
}

export default PagesManager;

import React, { useMemo, useState } from 'react';
import {
    Check, X, Search, Filter, ChevronDown, ChevronRight,
    Eye, Edit, Trash2, RotateCcw, CheckSquare, Square
} from 'lucide-react';
import { Input } from '@/components/ui/input';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';

// Defined Resource Categories for better organization
const RESOURCE_CATEGORIES = {
    'Content': [
        'blogs', 'pages', 'visual_pages', 'portfolio', 'testimonies',
        'announcements', 'promotions', 'products', 'product_types',
        'themes', 'widgets', 'templates', 'contact_messages'
    ],
    'Media': [
        'photo_gallery', 'photo_galleries', 'video_gallery', 'video_galleries',
        'files', 'media', 'galleries'
    ],
    'Commerce': [
        'orders', 'products', 'product_types'
    ],
    'System': [
        'users', 'roles', 'role', 'permissions', 'policies', 'policy', 'settings', 'setting',
        'audit', 'backups', 'extensions', 'languages', 'seo', 'sso', 'admin_menu',
        'sidebar_manager', 'sidebar', 'system'
    ],
    'Navigation': [
        'menus', 'categories', 'tags', 'navigation', 'admin_navigation'
    ],
    'Communication': [
        'contacts', 'contact_messages', 'notifications', 'messages', 'email'
    ],
    'Platform': [
        'tenant', 'tenants', 'platform', 'dashboard', '2fa', 'content', 'tenant.region'
    ],
    'Plugins': [
        'regions', 'mailketing', 'analytics'
    ],
    'Mobile & IoT': [
        'mobile', 'mobile_users', 'push_notifications', 'iot'
    ]
};



const ACTIONS = [
    { key: 'create', label: 'C', fullLabel: 'Create', icon: Edit, color: 'text-green-500', bg: 'bg-green-50', desc: 'Can create new items' },
    { key: 'read', label: 'R', fullLabel: 'Read', icon: Eye, color: 'text-blue-500', bg: 'bg-blue-50', desc: 'Can view list and details' },
    { key: 'update', label: 'U', fullLabel: 'Update', icon: Edit, color: 'text-amber-500', bg: 'bg-amber-50', desc: 'Can edit items (All or Own based on role)' },
    { key: 'publish', label: 'P', fullLabel: 'Publish', icon: Check, color: 'text-indigo-500', bg: 'bg-indigo-50', desc: 'Can publish content live' },
    { key: 'soft_delete', label: 'SD', fullLabel: 'Soft Delete', icon: Trash2, color: 'text-orange-500', bg: 'bg-orange-50', desc: 'Can move items to trash' },
    { key: 'restore', label: 'RS', fullLabel: 'Restore', icon: RotateCcw, color: 'text-cyan-500', bg: 'bg-cyan-50', desc: 'Can restore items from trash' },
    { key: 'delete_permanent', label: 'DP', fullLabel: 'Delete Permanent', icon: X, color: 'text-rose-600', bg: 'bg-rose-50', desc: 'Can permanently delete (irreversible)' }
];

// Map UI keys to potential legacy DB action names for backwards compatibility
const ACTION_ALIASES = {
    'create': ['create'],
    'read': ['read', 'view'],
    'update': ['update', 'edit'],
    'publish': ['publish'],
    'soft_delete': ['soft_delete', 'delete'],
    'restore': ['restore'],
    'delete_permanent': ['delete_permanent', 'permanent_delete']
};

const getPermissionId = (map, resource, actionKey) => {
    if (!map[resource]) return null;

    // Check aliases
    const aliases = ACTION_ALIASES[actionKey] || [actionKey];
    for (const alias of aliases) {
        if (map[resource][alias]) return map[resource][alias];
    }
    return null;
};

const PermissionMatrix = ({ permissions = [], selectedPermissions = new Set(), onToggle, readOnly = false }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [filterCategory, setFilterCategory] = useState('All');
    const [collapsedCategories, setCollapsedCategories] = useState({});

    // 1. Group Permissions by Resource for easy lookup
    // Map: resource -> action -> permissionId
    const permissionMap = useMemo(() => {
        const map = {};
        permissions.forEach(p => {
            if (!map[p.resource]) map[p.resource] = {};
            map[p.resource][p.action] = p.id;
        });
        return map;
    }, [permissions]);

    // 2. Identify all unique resources from permissions list
    const allResources = useMemo(() => Object.keys(permissionMap).sort(), [permissionMap]);

    // 3. Filter and Group Resources
    const filteredResources = useMemo(() => {
        let resources = allResources;

        if (searchTerm) {
            resources = resources.filter(r => r.toLowerCase().includes(searchTerm.toLowerCase()));
        }

        const grouped = {};
        const uncategorized = [];

        resources.forEach(res => {
            let found = false;
            for (const [cat, items] of Object.entries(RESOURCE_CATEGORIES)) {
                if (items.includes(res)) {
                    if (!grouped[cat]) grouped[cat] = [];
                    grouped[cat].push(res);
                    found = true;
                    break;
                }
            }
            if (!found) uncategorized.push(res);
        });

        if (uncategorized.length > 0) grouped['Other'] = uncategorized;

        // Apply category filter
        if (filterCategory !== 'All') {
            return { [filterCategory]: grouped[filterCategory] || [] };
        }

        return grouped;
    }, [allResources, searchTerm, filterCategory]);

    const flatResources = useMemo(() => Object.values(filteredResources).flat(), [filteredResources]);
    const visibleResourceCount = flatResources.length;
    const totalResourceCount = allResources.length;
    const selectedCount = selectedPermissions?.size || 0;

    const toggleCategory = (cat) => {
        setCollapsedCategories(prev => ({ ...prev, [cat]: !prev[cat] }));
    };

    const handleBulkToggle = (resource, shouldSelect) => {
        if (readOnly) return;
        const permissionIds = [];
        ACTIONS.forEach(action => {
            const pid = getPermissionId(permissionMap, resource, action.key);
            if (pid) permissionIds.push(pid);
        });

        // We need to pass individual IDs to parent
        permissionIds.forEach(pid => {
            if (selectedPermissions.has(pid) !== shouldSelect) {
                onToggle(pid);
            }
        });
    };

    // Calculate row stats
    const getRowStats = (resource) => {
        let total = 0;
        let selected = 0;
        ACTIONS.forEach(action => {
            const pid = getPermissionId(permissionMap, resource, action.key);
            if (pid) {
                total++;
                if (selectedPermissions.has(pid)) selected++;
            }
        });
        return { total, selected, all: total > 0 && total === selected };
    };

    return (
        <div className="space-y-4">
            {/* Toolbar */}
            <div className="flex flex-col sm:flex-row gap-4 justify-between items-start sm:items-center bg-slate-50 p-3 rounded-lg border border-slate-200">
                <div className="flex items-center gap-2 w-full sm:w-auto">
                    <div className="relative w-full sm:w-64">
                        <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                        <Input
                            placeholder="Search resources..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-9 bg-white"
                        />
                    </div>
                </div>
                <div className="flex items-center gap-2 overflow-x-auto w-full sm:w-auto pb-2 sm:pb-0">
                    <Filter className="w-4 h-4 text-slate-400" />
                    <div className="flex gap-1">
                        <button
                            type="button"
                            onClick={() => setFilterCategory('All')}
                            className={`px-3 py-1 rounded-full text-xs font-medium transition-colors whitespace-nowrap ${filterCategory === 'All' ? 'bg-slate-800 text-white' : 'bg-white border text-slate-600 hover:bg-slate-100'}`}
                        >
                            All
                        </button>
                        {Object.keys(RESOURCE_CATEGORIES).map(cat => (
                            <button
                                type="button"
                                key={cat}
                                onClick={() => setFilterCategory(cat)}
                                className={`px-3 py-1 rounded-full text-xs font-medium transition-colors whitespace-nowrap ${filterCategory === cat ? 'bg-slate-800 text-white' : 'bg-white border text-slate-600 hover:bg-slate-100'}`}
                            >
                                {cat}
                            </button>
                        ))}
                    </div>
                </div>
                <div className="flex items-center gap-2 text-xs text-slate-500 w-full sm:w-auto sm:justify-end">
                    <span>{visibleResourceCount} of {totalResourceCount} resources</span>
                    <span className="hidden sm:inline">•</span>
                    <span>{selectedCount} / {permissions.length} granted</span>
                </div>
            </div>

            {/* Matrix Grid */}
            <div className="border rounded-lg overflow-hidden bg-white dark:bg-slate-900 shadow-sm ring-1 ring-slate-200 dark:ring-slate-700">
                <div className="max-h-[60vh] overflow-auto custom-scrollbar">
                    <table className="w-full text-sm min-w-[900px] table-fixed">
                        <colgroup>
                            <col className="w-[220px] min-w-[220px]" />
                            {ACTIONS.map(action => (
                                <col key={`col-${action.key}`} className="w-[72px]" />
                            ))}
                            <col className="w-[60px]" />
                        </colgroup>
                        <thead className="sticky top-0 z-30">
                            <tr className="bg-slate-50/95 dark:bg-slate-800/95 border-b border-slate-200 dark:border-slate-700 backdrop-blur-sm">
                                <th className="p-3 text-left font-bold text-slate-700 dark:text-slate-200 w-[220px] min-w-[220px] sticky left-0 bg-slate-50/95 dark:bg-slate-800/95 z-30 shadow-[2px_0_8px_-2px_rgba(0,0,0,0.1)] dark:shadow-[2px_0_8px_-2px_rgba(0,0,0,0.3)]">
                                    Module / Resource
                                </th>
                                {ACTIONS.map(action => (
                                    <th key={action.key} className="p-2 text-center font-semibold text-slate-600 dark:text-slate-300 w-[72px]">
                                        <TooltipProvider>
                                            <Tooltip>
                                                <TooltipTrigger className="flex flex-col items-center justify-center gap-0.5 cursor-help group w-full">
                                                    <div className={`p-1 rounded-md ${action.bg} dark:opacity-90 ${action.color} group-hover:scale-110 transition-transform`}>
                                                        <action.icon className="w-3.5 h-3.5" />
                                                    </div>
                                                    <span className="text-[10px] font-medium">{action.label}</span>
                                                </TooltipTrigger>
                                                <TooltipContent className="dark:bg-slate-800 dark:text-slate-200">
                                                    <p>{action.desc}</p>
                                                </TooltipContent>
                                            </Tooltip>
                                        </TooltipProvider>
                                    </th>
                                ))}
                                <th className="p-2 text-center font-semibold text-slate-600 dark:text-slate-300 w-[60px] sticky right-0 bg-slate-50/95 dark:bg-slate-800/95 z-30 shadow-[-2px_0_8px_-2px_rgba(0,0,0,0.1)] dark:shadow-[-2px_0_8px_-2px_rgba(0,0,0,0.3)]">
                                    <span className="text-[10px]">All</span>
                                </th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                            {visibleResourceCount === 0 ? (
                                <tr>
                                    <td colSpan={ACTIONS.length + 2} className="p-8 text-center text-sm text-slate-500 dark:text-slate-400">
                                        No permissions match the current filters.
                                    </td>
                                </tr>
                            ) : (
                                Object.entries(filteredResources).map(([category, resources]) => {
                                    if (resources.length === 0) return null;
                                    const isCollapsed = collapsedCategories[category];

                                    return (
                                        <React.Fragment key={category}>
                                            {/* Category Header */}
                                            <tr className="bg-slate-100/70 dark:bg-slate-800/70 hover:bg-slate-100 dark:hover:bg-slate-700 cursor-pointer" onClick={() => toggleCategory(category)}>
                                                <td colSpan={ACTIONS.length + 2} className="px-3 py-2 font-semibold text-xs text-slate-500 dark:text-slate-400 uppercase tracking-wider sticky left-0 z-10 bg-slate-100/70 dark:bg-slate-800/70">
                                                    <div className="flex items-center gap-2">
                                                        {isCollapsed ? <ChevronRight className="w-3.5 h-3.5" /> : <ChevronDown className="w-3.5 h-3.5" />}
                                                        {category} <span className="bg-slate-200 dark:bg-slate-600 text-slate-600 dark:text-slate-200 px-1.5 py-0.5 rounded-full text-[10px]">{resources.length}</span>
                                                    </div>
                                                </td>
                                            </tr>

                                            {/* Resources */}
                                            {!isCollapsed && resources.map((resource) => {
                                                const stats = getRowStats(resource);
                                                const resourceLabel = resource.replace(/[_\.]/g, ' ');

                                                return (
                                                    <tr key={resource} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group">
                                                        <td className="p-3 font-medium text-slate-800 dark:text-slate-200 bg-white dark:bg-slate-900 sticky left-0 z-10 shadow-[2px_0_8px_-2px_rgba(0,0,0,0.08)] dark:shadow-[2px_0_8px_-2px_rgba(0,0,0,0.25)] capitalize border-r border-slate-100 dark:border-slate-700 group-hover:bg-slate-50 dark:group-hover:bg-slate-800/50 transition-colors">
                                                            <div className="flex items-center gap-2">
                                                                {resourceLabel}
                                                            </div>
                                                        </td>
                                                        {ACTIONS.map(action => {
                                                            const permId = getPermissionId(permissionMap, resource, action.key);

                                                            // If permission doesn't exist for this resource
                                                            if (!permId) {
                                                                return <td key={action.key} className="p-1.5 text-center bg-slate-50/30 dark:bg-slate-800/30" title="Not available">
                                                                    <div className="w-1.5 h-1.5 rounded-full bg-slate-200 dark:bg-slate-600 mx-auto" />
                                                                </td>;
                                                            }

                                                            const isSelected = selectedPermissions.has(permId);

                                                            return (
                                                                <td key={action.key} className="p-1.5 text-center">
                                                                    <button
                                                                        type="button"
                                                                        disabled={readOnly}
                                                                        onClick={() => onToggle(permId)}
                                                                        className={`
                                                                            w-8 h-8 rounded-lg flex items-center justify-center transition-all mx-auto duration-200
                                                                            ${isSelected
                                                                                ? `${action.bg} dark:opacity-90 ${action.color} shadow-sm ring-1 ring-inset ring-black/5 dark:ring-white/10 scale-100`
                                                                                : 'bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-600 text-slate-300 dark:text-slate-500 hover:border-slate-300 dark:hover:border-slate-500 hover:text-slate-400 scale-95 hover:scale-100'
                                                                            }
                                                                            ${readOnly ? 'cursor-default opacity-80' : 'cursor-pointer'}
                                                                        `}
                                                                        title={`${action.fullLabel} ${resourceLabel}`}
                                                                    >
                                                                        {isSelected ? <Check className="w-4 h-4" strokeWidth={3} /> : <X className="w-3.5 h-3.5" />}
                                                                    </button>
                                                                </td>
                                                            );
                                                        })}
                                                        {/* Bulk Action Column */}
                                                        <td className="p-1.5 text-center sticky right-0 bg-white dark:bg-slate-900 group-hover:bg-slate-50 dark:group-hover:bg-slate-800/50 z-10 shadow-[-2px_0_8px_-2px_rgba(0,0,0,0.08)] dark:shadow-[-2px_0_8px_-2px_rgba(0,0,0,0.25)] border-l border-slate-100 dark:border-slate-700">
                                                            <button
                                                                type="button"
                                                                disabled={readOnly}
                                                                onClick={() => handleBulkToggle(resource, !stats.all)}
                                                                className={`
                                                                    w-7 h-7 rounded-md flex items-center justify-center transition-all mx-auto
                                                                    ${stats.all
                                                                        ? 'text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/40 hover:bg-blue-100 dark:hover:bg-blue-900/60'
                                                                        : 'text-slate-400 dark:text-slate-500 hover:text-blue-500 hover:bg-slate-100 dark:hover:bg-slate-700'
                                                                    }
                                                                `}
                                                                title={stats.all ? 'Deselect All' : 'Select All'}
                                                            >
                                                                {stats.all ? <CheckSquare className="w-3.5 h-3.5" /> : <Square className="w-3.5 h-3.5" />}
                                                            </button>
                                                        </td>
                                                    </tr>
                                                );
                                            })}
                                        </React.Fragment>
                                    );
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-xs text-slate-500 dark:text-slate-400 bg-slate-50 dark:bg-slate-800/50 p-4 rounded-lg border border-slate-200 dark:border-slate-700">
                <div>
                    <h4 className="font-bold text-slate-700 dark:text-slate-200 mb-2">Legend</h4>
                    <div className="flex flex-wrap gap-2">
                        {ACTIONS.map(a => (
                            <div key={a.key} className="flex items-center gap-1.5">
                                <div className={`w-3 h-3 rounded-full ${a.bg} border ${a.color.replace('text', 'border')}`}></div>
                                <span><strong>{a.label}</strong>: {a.fullLabel}</span>
                            </div>
                        ))}
                    </div>
                </div>
                <div>
                    <h4 className="font-bold text-slate-700 dark:text-slate-200 mb-2">Permission Logic</h4>
                    <ul className="list-disc list-inside space-y-1 text-slate-600 dark:text-slate-400">
                        <li><strong>U (Update)</strong>: Authors can only edit <strong>their own</strong> content.</li>
                        <li><strong>RS (Restore)</strong>: Allows bringing items back from Trash.</li>
                        <li><strong>DP (Delete Permanent)</strong>: Irreversible. Reserved for platform admin roles.</li>
                    </ul>
                </div>
            </div>
        </div >
    );
};

export default PermissionMatrix;

