import React from 'react';
import { ImageIcon } from 'lucide-react';
import { PageLinkField } from '../fields/PageLinkField';
import { ImageField } from '../fields/ImageField';

export const StepsBlock = ({
    title,
    subtitle,
    tagline,
    items = [],
    image,
    isReversed
}) => {
    return (
        <section className="py-16 px-4 md:px-6 bg-white dark:bg-slate-950">
            <div className={`max-w-6xl mx-auto flex flex-col md:gap-12 ${isReversed ? 'md:flex-row-reverse' : 'md:flex-row'}`}>

                {/* Image Section */}
                <div className={`md:w-1/2 ${!image ? 'hidden md:block bg-slate-100 rounded-xl min-h-[400px]' : ''}`}>
                    {image ? (
                        <div className="sticky top-24">
                            <img
                                src={image}
                                alt={title}
                                className="w-full h-auto object-cover rounded-xl shadow-lg aspect-[4/5]"
                            />
                        </div>
                    ) : (
                        <div className="h-full w-full flex items-center justify-center text-slate-400">
                            <ImageIcon className="w-20 h-20" />
                        </div>
                    )}
                </div>

                {/* Content Section */}
                <div className={`md:w-1/2 flex flex-col justify-center ${!image ? 'md:w-full max-w-4xl mx-auto' : ''}`}>
                    {(title || subtitle || tagline) && (
                        <div className="mb-10">
                            {tagline && (
                                <p className="text-primary font-bold tracking-wide uppercase text-sm mb-2">{tagline}</p>
                            )}
                            {title && (
                                <h2 className="text-3xl md:text-4xl font-bold tracking-tight mb-4 text-slate-900 dark:text-white">
                                    {title}
                                </h2>
                            )}
                            {subtitle && (
                                <p className="text-lg text-slate-600 dark:text-slate-400 leading-relaxed">
                                    {subtitle}
                                </p>
                            )}
                        </div>
                    )}

                </div>
                {items.map((item, i) => (
                    <div key={i} className="flex gap-4 group">
                        <div className="flex flex-col items-center">
                            <div className="flex items-center justify-center w-10 h-10 rounded-full border-2 border-primary text-primary font-bold text-lg bg-white z-10 group-hover:bg-primary group-hover:text-white transition-colors">
                                {i + 1}
                            </div>
                            {i !== items.length - 1 && (
                                <div className="w-0.5 h-full bg-slate-200 dark:bg-slate-800 -my-2" />
                            )}
                        </div>
                        <div className="pb-8">
                            <h3 className="text-xl font-bold mb-2 text-slate-900 dark:text-white group-hover:text-primary transition-colors">
                                {item.title}
                            </h3>
                            <p className="text-slate-600 dark:text-slate-400 leading-relaxed">
                                {item.description}
                            </p>
                            {item.icon && (
                                <div className="mt-2 text-xs text-slate-400 font-mono">
                                    Icon: {item.icon}
                                </div>
                            )}
                        </div>
                    </div>
                ))}
            </div>

            {callToAction?.text && callToAction?.link && (
                <div className="mt-12 text-center">
                    <a
                        href={callToAction.link}
                        className="inline-flex items-center justify-center bg-primary text-white px-8 py-3 rounded-full font-bold text-lg shadow-lg hover:bg-primary/90 hover:scale-105 transition-all"
                    >
                        {callToAction.text}
                    </a>
                </div>
            )}
        </section >
    );
};

export const StepsBlockFields = {
    isReversed: {
        type: 'radio',
        label: 'Reverse Layout',
        options: [
            { label: 'No', value: false },
            { label: 'Yes', value: true }
        ]
    },
    image: { type: 'custom', label: 'Image', render: ImageField },
    tagline: { type: 'text', label: 'Tagline' },
    title: { type: 'text', label: 'Title' },
    subtitle: { type: 'textarea', label: 'Subtitle' },
    items: {
        type: 'array',
        getItemSummary: (item) => item.title || 'Step Item',
        arrayFields: {
            title: { type: 'text', label: 'Title' },
            description: { type: 'textarea', label: 'Description' },
            icon: { type: 'text', label: 'Icon (e.g. tabler:package)' }
        },
        defaultItemProps: {
            title: 'New Step',
            description: 'Description of this step.',
            icon: 'tabler:check'
        }
    },
    callToAction: {
        type: 'object',
        objectFields: {
            text: { type: 'text', label: 'Button Text' },
            link: { type: 'custom', label: 'Button Link', render: PageLinkField }
        }
    }
};

import React, { useState, useEffect } from 'react';
import { Select, SelectContent, SelectGroup, SelectItem, SelectLabel, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { udm } from '@/lib/data/UnifiedDataManager';
import { Loader2, Link as LinkIcon, ExternalLink } from 'lucide-react';

export const PageLinkField = ({ name, value, onChange, field }) => {
    const [activeTab, setActiveTab] = useState('internal');
    const [pages, setPages] = useState([]);
    const [loading, setLoading] = useState(false);
    const [customUrl, setCustomUrl] = useState('');
    const [internalSlugs, setInternalSlugs] = useState(new Set());

    // Initialize state based on incoming value
    useEffect(() => {
        if (value) {
            // Check if it looks like an internal link (starts with / and not //)
            const isInternal = value.startsWith('/') && !value.startsWith('//');

            if (isInternal) {
                setActiveTab('internal');
            } else {
                setActiveTab('custom');
                setCustomUrl(value);
            }
        }
    }, []); // Only run on mount to set initial tab

    // Fetch available pages and blogs
    useEffect(() => {
        const fetchPages = async () => {
            setLoading(true);
            try {
                // Fetch Pages
                const { data: pagesData, error: pagesError } = await udm.from('pages')
                    .select('id, title, slug, page_type')
                    .eq('status', 'published');

                if (pagesError) console.error("Error fetching pages:", pagesError);

                // Fetch Blogs
                const { data: blogsData, error: blogsError } = await udm.from('blogs')
                    .select('id, title, slug')
                    .eq('status', 'published');

                if (blogsError) console.error("Error fetching blogs:", blogsError);

                const formattedPages = (pagesData || []).map(p => ({
                    label: p.title,
                    value: `/${p.slug}`,
                    type: 'Page'
                }));

                const formattedBlogs = (blogsData || []).map(b => ({
                    label: b.title,
                    value: `/blog/${b.slug}`,
                    type: 'Blog'
                }));

                const allLinks = [...formattedPages, ...formattedBlogs];
                setPages(allLinks);
                setInternalSlugs(new Set(allLinks.map(l => l.value)));

            } catch (error) {
                console.error("Error fetching link options:", error);
            } finally {
                setLoading(false);
            }
        };

        fetchPages();
    }, []);

    const handleInternalChange = (val) => {
        onChange(val);
    };

    const handleCustomChange = (e) => {
        const val = e.target.value;
        setCustomUrl(val);
        onChange(val);
    };

    // Update custom URL input if user switches to custom tab and value is present
    const handleTabChange = (val) => {
        setActiveTab(val);
        if (val === 'custom' && value && !value.startsWith('/') && !value.startsWith('//')) {
            setCustomUrl(value);
        } else if (val === 'custom' && !customUrl && value) {
            // If switching to custom and we have a value that might be internal, keep it as custom input
            setCustomUrl(value);
        }
    };

    return (
        <div className="space-y-3">
            <Label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">{field.label || name}</Label>

            <Tabs value={activeTab} onValueChange={handleTabChange} className="w-full">
                <TabsList className="grid w-full grid-cols-2 h-8">
                    <TabsTrigger value="internal" className="text-xs">Internal Page</TabsTrigger>
                    <TabsTrigger value="custom" className="text-xs">Custom URL</TabsTrigger>
                </TabsList>

                <TabsContent value="internal" className="mt-2 space-y-2">
                    {loading ? (
                        <div className="flex items-center text-xs text-muted-foreground py-2">
                            <Loader2 className="mr-2 h-3 w-3 animate-spin" /> Loading pages...
                        </div>
                    ) : (
                        <Select value={activeTab === 'internal' && pages.some(p => p.value === value) ? value : ''} onValueChange={handleInternalChange}>
                            <SelectTrigger className="h-9 w-full">
                                <SelectValue placeholder="Select a page..." />
                            </SelectTrigger>
                            <SelectContent className="max-h-[200px]">
                                <SelectGroup>
                                    <SelectLabel>Pages</SelectLabel>
                                    {pages.filter(p => p.type === 'Page').map(p => (
                                        <SelectItem key={p.value} value={p.value}>
                                            <span className="truncate block max-w-[200px]">{p.label}</span>
                                        </SelectItem>
                                    ))}
                                </SelectGroup>
                                {pages.some(p => p.type === 'Blog') && (
                                    <SelectGroup>
                                        <SelectLabel>Blogs</SelectLabel>
                                        {pages.filter(p => p.type === 'Blog').map(p => (
                                            <SelectItem key={p.value} value={p.value}>
                                                <span className="truncate block max-w-[200px]">{p.label}</span>
                                            </SelectItem>
                                        ))}
                                    </SelectGroup>
                                )}
                            </SelectContent>
                        </Select>
                    )}
                    <div className="text-[10px] text-muted-foreground flex items-center bg-slate-50 dark:bg-slate-900 p-1.5 rounded border border-slate-100 dark:border-slate-800">
                        <LinkIcon className="w-3 h-3 mr-1.5 opacity-70" />
                        <span className="font-mono truncate">{value || '(empty)'}</span>
                    </div>
                </TabsContent>

                <TabsContent value="custom" className="mt-2">
                    <div className="relative">
                        <Input
                            placeholder="https://example.com or #section"
                            value={customUrl}
                            onChange={handleCustomChange}
                            className="h-9 text-sm pr-8"
                        />
                        <ExternalLink className="absolute right-3 top-2.5 h-4 w-4 text-slate-400" />
                    </div>
                    <div className="text-[10px] text-muted-foreground mt-1.5">
                        Enter full URL (https://...) or fragment (#section)
                    </div>
                </TabsContent>
            </Tabs>
        </div>
    );
};

